import sys
def solve():
    data=list(map(int,sys.stdin.read().strip().split()))
    if not data:
        return
    it=iter(data)
    T=next(it)
    out=[]
    for _ in range(T):
        N=next(it); X=next(it)
        A=[next(it) for _ in range(N)]
        dp=[False]*(X+1)
        dp[0]=True
        for a in A:
            for s in range(X, a-1, -1):
                if dp[s-a]:
                    dp[s]=True
        out.append('YES' if dp[X] else 'NO')
    sys.stdout.write('\n'.join(out))
if __name__=='__main__':
    solve()

